function EditObject({ doubleClickedObjId, objects, setObjects }) {
    function newSkin(color) {
        setObjects(
            objects.map((el) =>
                el.id === doubleClickedObjId ? { ...el, color: color } : el,
            ),
        );
    }

    const selectedObject = objects.find((el) => el.id === doubleClickedObjId);

    return (
        <div className="editObj">
            <h2>Edit object</h2>
            <div className="editColor">
                <div className="editColorButtons">
                    <button className="colEditGreen" onClick={newSkin("green")} />
                    <button className="colEditBlue" />
                    <button className="colEditYellow" />
                    <button className="colEditGrey" />
                    <button className="colEditWhite" />
                    <button className="colEditPurple" />
                    <button className="colEditCyan" />
                    <button className="colEditLime" />
                    <button className="colEditRed" />
                    <button className="colEditBrown" />
                    <button className="colEditOrange" />
                    <button className="colEditLightBlue" />
                    <button className="colEditPink" />
                    <button className="colEditDarkStaleGrey" />
                </div>
                <p className="objPropName">Color</p>
            </div>
            <div className="editButtonForm">
                <button
                    className="objForm"
                    style={{
                        backgroundColor: selectedObject.color,
                    }}
                />
                <p className="objPropName">Circle</p>
            </div>
        </div>
    );
}

export default EditObject;
